const data = $input.first().json;
const hits = (data.hits || []).filter(h => h.title && h.points > 20);
hits.sort((a, b) => b.points - a.points);
const keywords = ['ai','gpt','llm','machine learning','automation','agent','cybersecurity','openai','python','ml','deep learning','model','neural','robot','data'];
const relevant = hits.filter(h => keywords.some(k => h.title.toLowerCase().includes(k))).slice(0, 5);
const pick = relevant[0] || hits[0] || { title: 'AI agents are replacing SaaS workflows in 2026', url: '', points: 100 };

const profileCtx = 'Aditya Sahani: AI Student (IBCP), 16, Python Developer, IIT Bombay Eureka Junior Top 100, built anomaly detection, AI scrapers, 14k leads/day automation pipeline, interested in AI, ML, Automation, Cybersecurity.';

const prompt = 'You are a top 1% LinkedIn strategist. Write a viral post for this student developer.\n\nAbout: ' + profileCtx + '\n\nTrending topic: "' + pick.title + '"\n\nRules:\n- 1-line scroll-stopping hook\n- Short sentences, mobile-friendly\n- Personal angle from his real projects\n- 1 key insight, 1 takeaway\n- End with question\n- Max 3 emojis\n\nReturn ONLY this JSON, no markdown:\n{"post":"full post here","hashtags":"#AI #tag2 #tag3 #tag4","best_time":"HH:MM IST","hook_preview":"first line only"}';

const openai_body = JSON.stringify({
  model: 'gpt-4.1-nano',
  max_tokens: 800,
  temperature: 0.85,
  messages: [
    { role: 'system', content: 'You are a top LinkedIn content strategist. Return ONLY valid JSON. No markdown. No explanation.' },
    { role: 'user',   content: prompt }
  ]
});

return [{ json: {
  trending_topic: pick.title,
  topic_url: pick.url || '',
  topic_points: pick.points || 0,
  openai_prompt: prompt,
  openai_body: openai_body,
  run_date: new Date().toLocaleDateString('en-IN', { timeZone: 'Asia/Kolkata' }),
  run_timestamp: new Date().toISOString()
} }];

const aiResp = $input.first().json;
const prev = $('Pick Topic and Build Prompt').first().json;

const isRateLimit = aiResp.error?.status === 429 || aiResp.status === 429 || JSON.stringify(aiResp).includes('429');

let p = {};
if (isRateLimit) {
  p = {
    post: 'Deep learning just got ears.\n\nResearchers built an AI that listens to machines — motors, pumps, turbines — and detects problems before they break.\n\nNo sensors. No manual checks. Just sound + AI.\n\nI built something similar at 16. My anomaly detection project flags unusual patterns in data streams automatically.\n\nThe principle is the same:\nTeach the model what normal sounds like.\nAnything else = alert.\n\nThis is not the future. This is running in factories right now.\n\nIf AI can hear a failing motor, what else can it sense before humans notice?',
    hashtags: '#AI #MachineLearning #AnomalyDetection #BuildInPublic',
    best_time: '11:00 IST',
    hook_preview: 'Deep learning just got ears.',
    used_fallback: true
  };
} else {
  try {
    const raw = aiResp.choices?.[0]?.message?.content || '{}';
    p = JSON.parse(raw.replace(/```json|```/gi,'').trim());
  } catch(e) {
    p = {
      post: 'I built an anomaly detection system at 16.\n\nNot for a grade. For real.\n\nThe gap between student project and real system is smaller than you think.\n\nYou just have to build like it matters.\n\nWhat is the most real thing you have built?',
      hashtags: '#AI #BuildInPublic #Automation #StudentDeveloper',
      best_time: '11:00 IST',
      hook_preview: 'I built an anomaly detection system at 16.'
    };
  }
}

const timeStr = (p.best_time || '11:00 IST').replace(' IST','');
const tp = timeStr.split(':');
let uh = (parseInt(tp[0])||11) - 5;
let um = (parseInt(tp[1])||0) - 30;
if (um < 0) { um += 60; uh -= 1; }
if (uh < 0) uh += 24;
const tom = new Date();
tom.setDate(tom.getDate()+1);
tom.setUTCHours(uh, um, 0, 0);

const fullPost = (p.post||'') + '\n\n' + (p.hashtags||'');
const fallbackNote = p.used_fallback ? '\n\n⚠️ _Rate limit hit — fallback post used_' : '';
const tgMsg = '\u{1F4DD} *LinkedIn Post Ready*' + (p.used_fallback ? ' _(fallback)_' : '') + '\n\n\u{1F4CC} *Topic:* ' + prev.trending_topic + '\n\u{23F0} *Post at:* ' + (p.best_time||'11:00 IST') + ' tomorrow' + fallbackNote + '\n\n' + '\u2500'.repeat(22) + '\n\n' + (p.post||'') + '\n\n' + (p.hashtags||'') + '\n\n' + '\u2500'.repeat(22) + '\n\n\u{1F447} Tap a button below';

const linkedin_body = JSON.stringify({
  author: 'urn:li:person:LINKEDIN_PERSON_URN_HERE',
  lifecycleState: 'PUBLISHED',
  specificContent: {
    'com.linkedin.ugc.ShareContent': {
      shareCommentary: { text: fullPost },
      shareMediaCategory: 'NONE'
    }
  },
  visibility: { 'com.linkedin.ugc.MemberNetworkVisibility': 'PUBLIC' }
});

return [{ json: {
  post_text:     p.post||'',
  full_post:     fullPost,
  hashtags:      p.hashtags||'#AI',
  best_time_ist: p.best_time||'11:00 IST',
  post_utc_iso:  tom.toISOString(),
  hook_preview:  p.hook_preview||'',
  telegram_msg:  tgMsg,
  topic_title:   prev.trending_topic,
  run_date:      prev.run_date,
  used_fallback: p.used_fallback || false,
  linkedin_body: linkedin_body
} }];

